1	import { useState, useRef, useEffect } from 'react'
2	import { useSortable } from '@dnd-kit/sortable'
3	import { CSS } from '@dnd-kit/utilities'
4	import './CardTile.css'
5	
6	export default function CardTile({ card, onCardClick, onUpdate }) {
7	  const [isEditingTitle, setIsEditingTitle]       = useState(false)
8	  const [editTitle, setEditTitle]                 = useState(card.title)
9	  const [isEditingAssignee, setIsEditingAssignee] = useState(false)
10	  const [editAssignee, setEditAssignee]           = useState(card.assignee ?? '')
11	  const [isSaving, setIsSaving]                   = useState(false)
12	  const [saveError, setSaveError]                 = useState(null)
13	  const skipTitleBlurRef                          = useRef(false)
14	  const skipAssigneeBlurRef                       = useRef(false)
15	  const titleInputRef                             = useRef(null)
16	  const assigneeInputRef                          = useRef(null)
17	
18	  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({ id: card.id })
19	
20	  const style = {
21	    transform: CSS.Transform.toString(transform),
22	    transition,
23	  }
24	
25	  // Auto-focus input when entering edit mode (mirrors CardModal pattern)
26	  useEffect(() => {
27	    if (isEditingTitle && titleInputRef.current) titleInputRef.current.focus()
28	  }, [isEditingTitle])
29	
30	  useEffect(() => {
31	    if (isEditingAssignee && assigneeInputRef.current) assigneeInputRef.current.focus()
32	  }, [isEditingAssignee])
33	
34	  async function handleSaveTitle() {
35	    if (editTitle.trim() === '') { setSaveError('Title is required'); return }
36	    setIsSaving(true); setSaveError(null)
37	    try {
38	      await onUpdate(card.id, { title: editTitle })
39	      setIsEditingTitle(false)
40	    } catch (err) {
41	      setSaveError(err.message)
42	    } finally { setIsSaving(false) }
43	  }
44	
45	  async function handleSaveAssignee() {
46	    setIsSaving(true); setSaveError(null)
47	    try {
48	      await onUpdate(card.id, { assignee: editAssignee === '' ? null : editAssignee })
49	      setIsEditingAssignee(false)
50	    } catch (err) {
51	      setSaveError(err.message)
52	    } finally { setIsSaving(false) }
53	  }
54	
55	  const isEditing = isEditingTitle || isEditingAssignee
56	
57	  const { onKeyDown: dndKeyDown, ...restListeners } = listeners ?? {}
58	
59	  function handleKeyDown(e) {
60	    if (isEditing) return
61	    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); onCardClick(card) }
62	    dndKeyDown?.(e)
63	  }
64	
65	  const classes = ['card-tile', isEditing && 'card-tile-editing', isDragging && 'card-tile-dragging']
66	    .filter(Boolean).join(' ')
67	
68	  return (
69	    <div
70	      ref={setNodeRef}
71	      style={style}
72	      className={classes}
73	      role="button"
74	      tabIndex={0}
75	      onClick={() => !isEditing && onCardClick(card)}
76	      onKeyDown={handleKeyDown}
77	      aria-label={card.title}
78	      {...attributes}
79	      {...restListeners}
80	    >
81	      {/* Title */}
82	      {isEditingTitle ? (
83	        <div className="card-tile-field-edit">
84	          <input
85	            ref={titleInputRef}
86	            aria-label="Edit title"
87	            value={editTitle}
88	            onChange={e => setEditTitle(e.target.value)}
89	            onKeyDown={e => {
90	              if (e.key === 'Enter')  { skipTitleBlurRef.current = true; handleSaveTitle() }
91	              if (e.key === 'Escape') { skipTitleBlurRef.current = true; setIsEditingTitle(false); setEditTitle(card.title); setSaveError(null) }
92	            }}
93	            onBlur={() => {
94	              if (skipTitleBlurRef.current) { skipTitleBlurRef.current = false; return }
95	              handleSaveTitle()
96	            }}
97	          />
98	          {isSaving && <span aria-label="Saving">Saving…</span>}
99	        </div>
100	      ) : (
101	        <h3
102	          className="card-tile-title"
103	          onClick={e => {
104	            e.stopPropagation()
105	            setEditTitle(card.title)
106	            setIsEditingTitle(true)
107	            // Mutual exclusivity: close assignee edit if open
108	            setIsEditingAssignee(false)
109	            setEditAssignee(card.assignee ?? '')
110	            setSaveError(null)
111	          }}
112	        >
113	          {card.title}
114	        </h3>
115	      )}
116	
117	      {/* Assignee */}
118	      {isEditingAssignee ? (
119	        <div className="card-tile-field-edit">
120	          <input
121	            ref={assigneeInputRef}
122	            aria-label="Edit assignee"
123	            value={editAssignee}
124	            onChange={e => setEditAssignee(e.target.value)}
125	            onKeyDown={e => {
126	              if (e.key === 'Enter')  { skipAssigneeBlurRef.current = true; handleSaveAssignee() }
127	              if (e.key === 'Escape') { skipAssigneeBlurRef.current = true; setIsEditingAssignee(false); setEditAssignee(card.assignee ?? ''); setSaveError(null) }
128	            }}
129	            onBlur={() => {
130	              if (skipAssigneeBlurRef.current) { skipAssigneeBlurRef.current = false; return }
131	              handleSaveAssignee()
132	            }}
133	          />
134	          {isSaving && <span aria-label="Saving">Saving…</span>}
135	        </div>
136	      ) : (
137	        <p
138	          className="card-tile-assignee"
139	          onClick={e => {
140	            e.stopPropagation()
141	            setEditAssignee(card.assignee ?? '')
142	            setIsEditingAssignee(true)
143	            // Mutual exclusivity: close title edit if open
144	            setIsEditingTitle(false)
145	            setEditTitle(card.title)
146	            setSaveError(null)
147	          }}
148	        >
149	          {card.assignee ?? 'Unassigned'}
150	        </p>
151	      )}
152	
153	      {card.description && <p className="card-tile-description">{card.description}</p>}
154	      {saveError && <p role="alert" className="card-tile-error">{saveError}</p>}
155	    </div>
156	  )
157	}
